133	// ExecutionCleanupLivenessProbe decides whether a cleanup candidate should be
134	// preserved because it is still live.
135	type ExecutionCleanupLivenessProbe interface {
136		IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string)
137	}
138	
139	// defaultExecutionCleanupLivenessProbe preserves preserved metadata, a temp
140	// execution directory referenced by the live run-state file, or a candidate
141	// with an unexpired liveness marker. Tests can override the probe to model
142	// more specific host behavior.
143	type defaultExecutionCleanupLivenessProbe struct{}
144	
145	func (defaultExecutionCleanupLivenessProbe) IsLive(meta ExecutionCleanupMetadata, runState *RunState, now time.Time) (bool, string) {
146		if meta.Preserved {
147			return true, "preserved metadata"
148		}
149		if meta.ActiveCandidateCycle {
150			return true, candidateCycleRecoveryReason(meta, "active candidate cycle")
151		}
152		if strings.TrimSpace(meta.CandidateRef) != "" {
153			return true, candidateCycleRecoveryReason(meta, "candidate ref recovery")
154		}
155		if runState != nil {
156			if strings.TrimSpace(runState.CandidateCyclePhase) != "" {
157				return true, candidateCycleRecoveryReason(candidateCycleMetadataFromRunState(*runState), "active candidate cycle")
158			}
159			if meta.WorktreePath != "" && filepath.Clean(runState.WorktreePath) == filepath.Clean(meta.WorktreePath) {
160				return true, "matched live run-state"
161			}
162			if meta.AttemptID != "" && runState.AttemptID == meta.AttemptID {
163				return true, "matched live run-state"
164			}
165		}
166		if meta.Liveness != nil {
167			if meta.Liveness.PID > 0 && trackerProcessAlive(meta.Liveness.PID) {
168				return true, "live pid"
169			}
170			if !meta.Liveness.ExpiresAt.IsZero() && now.Before(meta.Liveness.ExpiresAt) {
171				return true, "unexpired liveness"
172			}
173			if !meta.Liveness.RefreshedAt.IsZero() && now.Sub(meta.Liveness.RefreshedAt) <= 2*time.Minute {
174				return true, "fresh liveness"
175			}
176		}
177		return false, "stale liveness"
178	}
