223	// Cleanup scans the configured DDx temp worktree root, consults the project
224	// run-state file and git worktree registry, and conservatively removes stale
225	// DDx-owned temp resources.
226	func (m *ExecutionCleanupManager) Cleanup(ctx context.Context) (ExecutionCleanupSummary, error) {
227		_ = ctx
228	
229		summary := ExecutionCleanupSummary{
230			ProjectRoot: m.ProjectRoot,
231			TempRoot:    m.tempRoot(),
232		}
233		if summary.TempRoot == "" {
234			summary.TempRoot = executionCleanupTempRoot(m.ProjectRoot)
235		}
236		if summary.TempRoot == "" {
237			return summary, errors.New("execution cleanup: temp root is empty")
238		}
239		if m.ProjectRoot == "" {
240			return summary, errors.New("execution cleanup: project root is empty")
241		}
242		now := time.Now
243		if m.Now != nil {
244			now = m.Now
245		}
246		probe := m.Probe
247		if probe == nil {
248			probe = defaultExecutionCleanupLivenessProbe{}
249		}
250	
251		registered := map[string]struct{}{}
252		liveRunStates := map[string]struct{}{}
253		if m.GitOps != nil {
254			paths, err := m.GitOps.WorktreeList(m.ProjectRoot)
255			if err != nil {
256				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
257					Path:    m.ProjectRoot,
258					Class:   "git_worktree_list",
259					Message: err.Error(),
260				})
261			} else {
262				for _, p := range paths {
263					registered[filepath.Clean(p)] = struct{}{}
264				}
265			}
266		}
267	
268		runStates, runStateErr := ReadRunStates(m.ProjectRoot)
269		if runStateErr != nil {
270			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
271				Path:    runStateDirPath(m.ProjectRoot),
272				Class:   "run_state_read",
273				Message: runStateErr.Error(),
274			})
275		}
276	
277		entries, err := os.ReadDir(summary.TempRoot)
278		if err != nil {
279			return summary, fmt.Errorf("execution cleanup: read temp root: %w", err)
280		}
281		for _, entry := range entries {
282			if !entry.IsDir() {
283				continue
284			}
285			if !strings.HasPrefix(entry.Name(), ExecuteBeadWtPrefix) {
286				continue
287			}
288			summary.ScannedTempDirs++
289			path := filepath.Join(summary.TempRoot, entry.Name())
290	
291			meta, metaErr := ReadExecutionCleanupMetadata(path)
292			missingMetadata := false
293			if metaErr != nil {
294				if errors.Is(metaErr, os.ErrNotExist) {
295					missingMetadata = true
296					meta = ExecutionCleanupMetadata{
297						ProjectRoot:  m.ProjectRoot,
298						WorktreePath: path,
299					}
300				} else {
301					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
302						Path:    path,
303						Class:   "metadata_read",
304						Message: metaErr.Error(),
305					})
306					continue
307				}
308			}
309			candidateRunStates := runStates
310			ownershipMismatch := meta.ProjectRoot != "" && !sameCleanPath(meta.ProjectRoot, m.ProjectRoot)
311			if ownershipMismatch {
312				candidateRunStates = m.runStatesForMetadata(meta, runStates, &summary)
313			}
314	
315			matchedRunState := matchingRunStateForMeta(candidateRunStates, meta)
316			live, reason := probe.IsLive(meta, matchedRunState, now())
317			if live {
318				if matchedRunState != nil {
319					liveRunStates[runStateLiveKey(*matchedRunState)] = struct{}{}
320				}
321				class := "preserved_temp_dir"
322				if isLiveAttemptPreservation(reason) {
323					class = "preserved_live_attempt"
324				}
325				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
326					Path:    path,
327					Class:   class,
328					Message: reason,
329				})
330				continue
331			}
332			if ownershipMismatch {
333				if !m.canReclaimForeignTestOwnedPath(meta.ProjectRoot, path) {
334					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
335						Path:    path,
336						Class:   "ownership_mismatch",
337						Message: fmt.Sprintf("metadata project_root=%s does not match manager project_root=%s", meta.ProjectRoot, m.ProjectRoot),
338					})
339					continue
340				}
341				if m.isRegisteredWorktree(meta.ProjectRoot, path, &summary) {
342					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
343						Path:    path,
344						Class:   "preserved_foreign_registered_worktree",
345						Message: "foreign project worktree is still registered",
346					})
347					continue
348				}
349			}
350	
351			if _, ok := registered[filepath.Clean(path)]; ok {
352				if missingMetadata {
353					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
354						Path:    path,
355						Class:   "registered_missing_metadata",
356						Message: "registered DDx worktree has no cleanup metadata; preserving",
357					})
358					summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
359						Path:    path,
360						Class:   "preserved_registered_missing_metadata",
361						Message: "registered worktree without cleanup metadata",
362					})
363					continue
364				}
365				if m.GitOps == nil {
366					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
367						Path:     path,
368						Class:    "registered_worktree",
369						Message:  "no git ops available to remove registered worktree",
370						Blocking: true,
371					})
372					continue
373				}
374				reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
375				if measureErr != nil {
376					summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
377						Path:    path,
378						Class:   "measure_tree",
379						Message: measureErr.Error(),
380					})
381				}
382				if !m.DryRun {
383					if err := m.GitOps.WorktreeRemove(m.ProjectRoot, path); err != nil {
384						summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
385							Path:     path,
386							Class:    "registered_worktree_remove",
387							Message:  err.Error(),
388							Blocking: true,
389						})
390						continue
391					}
392				}
393				summary.RemovedRegisteredWorktrees++
394				summary.BytesReclaimed += reclaimedBytes
395				summary.InodesReclaimed += reclaimedInodes
396				class := "removed_registered_worktree"
397				if m.DryRun {
398					class = "would_remove_registered_worktree"
399				}
400				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
401					Path:    path,
402					Class:   class,
403					Message: reason,
404					Bytes:   reclaimedBytes,
405					Inodes:  reclaimedInodes,
406				})
407				continue
408			}
409	
410			reclaimedBytes, reclaimedInodes, measureErr := measureTree(path)
411			if measureErr != nil {
412				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
413					Path:    path,
414					Class:   "measure_tree",
415					Message: measureErr.Error(),
416				})
417			}
418			if !m.DryRun {
419				if err := os.RemoveAll(path); err != nil {
420					summary.Issues = append(summary.Issues, ExecutionCleanupIssue{
421						Path:     path,
422						Class:    "unregistered_temp_dir_remove",
423						Message:  err.Error(),
424						Blocking: false,
425					})
426					continue
427				}
428			}
429			summary.RemovedUnregisteredTempDirs++
430			summary.BytesReclaimed += reclaimedBytes
431			summary.InodesReclaimed += reclaimedInodes
432			class := "removed_unregistered_temp_dir"
433			if m.DryRun {
434				class = "would_remove_unregistered_temp_dir"
435			}
436			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
437				Path:    path,
438				Class:   class,
439				Message: reason,
440				Bytes:   reclaimedBytes,
441				Inodes:  reclaimedInodes,
442			})
443		}
444	
445		m.cleanupScratchRoots(&summary, runStates, registered, probe, now())
446	
447		if m.GitOps != nil && summary.RemovedRegisteredWorktrees > 0 && !m.DryRun {
448			if err := m.GitOps.WorktreePrune(m.ProjectRoot); err != nil {
449				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
450					Path:    m.ProjectRoot,
451					Class:   "worktree_prune",
452					Message: err.Error(),
453				})
454			}
455		}
456	
457		// Stale run-state files are removed when they point at an execution
458		// resource that is no longer live.
459		for _, state := range runStates {
460			if _, ok := liveRunStates[runStateLiveKey(state)]; ok {
461				continue
462			}
463			if runStateWorktreeStillExists(state) {
464				continue
465			}
466			if removed, bytes := m.removeStaleRunState(state, &summary); removed {
467				summary.RemovedRunStateFiles++
468				summary.BytesReclaimed += bytes
469				summary.InodesReclaimed++
470			}
471		}
472	
473		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ExecuteBeadArtifactDir, "manifest.json", "result.json", &summary)
474		m.pruneEvidenceDirs(ctx, &summary, runStates, now())
475		summary.ScannedEvidenceDirs += scanCompleteEvidenceDirs(m.ProjectRoot, ".ddx/runs", "record.json", "", &summary)
476		m.cleanupDurableLandedCandidateRefs(&summary)
477	
478		return summary, nil
479	}
