// pruneAgentLogs deletes .ddx/agent-logs/agent-*.jsonl and svc-*.jsonl files
// whose mtime is older than m.RetainDays. Files referenced by an active
// run-state session are skipped. No-op when RetainDays == 0 (disabled).
func (m *ExecutionCleanupManager) pruneAgentLogs(summary *ExecutionCleanupSummary, runStates []RunState, now time.Time) {
	if m.RetainDays == 0 {
		return
	}
	cutoff := now.AddDate(0, 0, -m.RetainDays)

	activeSessions := map[string]struct{}{}
	for _, rs := range runStates {
		if rs.SessionID != "" {
			activeSessions[rs.SessionID] = struct{}{}
		}
	}

	logsDir := filepath.Join(m.ProjectRoot, ".ddx", "agent-logs")
	entries, err := os.ReadDir(logsDir)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    logsDir,
				Class:   "agent_logs_read",
				Message: err.Error(),
			})
		}
		return
	}

	for _, entry := range entries {
		if entry.IsDir() {
			continue
		}
		name := entry.Name()
		if !isAgentLogFile(name) {
			continue
		}

		sessionID := extractAgentLogSessionID(name)
		if sessionID != "" {
			if _, ok := activeSessions[sessionID]; ok {
				summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
					Path:    filepath.ToSlash(filepath.Join(".ddx/agent-logs", name)),
					Class:   "preserved_active_agent_log",
					Message: "active run-state session reference",
				})
				continue
			}
		}

		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    filepath.Join(logsDir, name),
				Class:   "agent_log_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		filePath := filepath.Join(logsDir, name)
		if !m.DryRun {
			if err := os.Remove(filePath); err != nil && !errors.Is(err, os.ErrNotExist) {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    filePath,
					Class:   "agent_log_remove",
					Message: err.Error(),
				})
				continue
			}
		}
		summary.RemovedAgentLogs++
		class := "removed_agent_log"
		if m.DryRun {
			class = "would_remove_agent_log"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    filepath.ToSlash(filepath.Join(".ddx/agent-logs", name)),
			Class:   class,
			Message: fmt.Sprintf("agent log older than %d days", m.RetainDays),
		})
	}
}

// pruneWorkerDirs deletes .ddx/workers/<id>/ directories whose mtime is older
// than m.RetainDays. Directories whose status.json records a live PID are
// skipped. No-op when RetainDays == 0 (disabled).
func (m *ExecutionCleanupManager) pruneWorkerDirs(summary *ExecutionCleanupSummary, now time.Time) {
	if m.RetainDays == 0 {
		return
	}
	cutoff := now.AddDate(0, 0, -m.RetainDays)

	workersDir := filepath.Join(m.ProjectRoot, ".ddx", "workers")
	entries, err := os.ReadDir(workersDir)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    workersDir,
				Class:   "workers_dir_read",
				Message: err.Error(),
			})
		}
		return
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		dirPath := filepath.Join(workersDir, entry.Name())

		if workerDirIsActive(dirPath) {
			summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
				Path:    filepath.ToSlash(filepath.Join(".ddx/workers", entry.Name())),
				Class:   "preserved_active_worker_dir",
				Message: "live worker PID",
			})
			continue
		}

		info, infoErr := entry.Info()
		if infoErr != nil {
			summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
				Path:    dirPath,
				Class:   "worker_dir_stat",
				Message: infoErr.Error(),
			})
			continue
		}
		if !info.ModTime().Before(cutoff) {
			continue
		}

		if !m.DryRun {
			if err := os.RemoveAll(dirPath); err != nil {
				summary.Warnings = append(summary.Warnings, ExecutionCleanupWarning{
					Path:    dirPath,
					Class:   "worker_dir_remove",
					Message: err.Error(),
				})
				continue
			}
		}
		summary.RemovedWorkerDirs++
		class := "removed_worker_dir"
		if m.DryRun {
			class = "would_remove_worker_dir"
		}
		summary.Observations = append(summary.Observations, ExecutionCleanupObservation{
			Path:    filepath.ToSlash(filepath.Join(".ddx/workers", entry.Name())),
			Class:   class,
			Message: fmt.Sprintf("worker dir older than %d days", m.RetainDays),
		})
	}
}

// workerDirIsActive returns true when the worker's status.json records a
// live OS process (PID > 0 and the process is still running).
func workerDirIsActive(dirPath string) bool {
	data, err := os.ReadFile(filepath.Join(dirPath, "status.json"))
	if err != nil {
		return false
	}
	var status struct {
		PID int `json:"pid"`
	}
	if err := json.Unmarshal(data, &status); err != nil {
		return false
	}
	return status.PID > 0 && trackerProcessAlive(status.PID)
}

// isAgentLogFile returns true for agent-*.jsonl and svc-*.jsonl filenames.
func isAgentLogFile(name string) bool {
	return (strings.HasPrefix(name, "agent-") || strings.HasPrefix(name, "svc-")) &&
		strings.HasSuffix(name, ".jsonl")
}

// extractAgentLogSessionID returns the session ID embedded in an agent log
// filename (agent-<sessionID>.jsonl or svc-<sessionID>.jsonl).
func extractAgentLogSessionID(name string) string {
	for _, prefix := range []string{"agent-", "svc-"} {
		if strings.HasPrefix(name, prefix) && strings.HasSuffix(name, ".jsonl") {
			return strings.TrimSuffix(strings.TrimPrefix(name, prefix), ".jsonl")
		}
	}
	return ""
}

